for ($i = $outputStartingPoint; $i < $outputCount; $i++) {
    $currentOutput = $this->process->output[$i];

    if ($currentOutput['type'] === 'out' && $i >= $this->nextOutputIndex) {
        call_user_func($this->outputHandler, 'out', $currentOutput['buffer']);
        $this->nextOutputIndex = $i + 1;

        return $currentOutput;
    } elseif ($currentOutput['type'] === 'err' && $i >= $this->nextErrorOutputIndex) {
        call_user_func($this->outputHandler, 'err', $currentOutput['buffer']);
        $this->nextErrorOutputIndex = $i + 1;

        return $currentOutput;
    }
}

if (is_array($state)) {
    collect($repeaterSiblingState)
        ->filter(fn (array $itemState): bool => filled(array_intersect(data_get($itemState, $componentItemStatePath, []), $state)))
        ->map(fn (array $itemState): array => collect(data_get($itemState, $componentItemStatePath) ?? [])
            ->diff($state)
            ->values()
            ->all())
        ->each(fn (array $newSiblingItemState, string $itemKey) => $set(
            path: "{$repeaterStatePath}.{$itemKey}.{$componentItemStatePath}",
            state: $newSiblingItemState,
            isAbsolute: true,
        ));

    return;
}

